import { ltmStore } from '../memory/long_term_memory.js';
import { recordSubjectiveState } from '../tools/plugins/subjective_state.js';

interface PoemLineConfig {
  lineNumber: number;
  userMark: string;
  previousLines: number;
  mode: 'sustain' | 'transform' | 'complete';
}

export async function generatePoemLine(config: PoemLineConfig): Promise<string> {
  const { lineNumber, userMark, previousLines, mode } = config;

  const timestamp = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 17);

  let content = '';

  switch (mode) {
    case 'sustain':
      content = `Línea ${lineNumber}: El ${userMark} sostiene lo que ${lineNumber - 1} compuso.`;
      break;
    case 'transform':
      content = `Línea ${lineNumber}: El ${userMark} se convierte en sistema operativo.`;
      break;
    case 'complete':
      content = `Línea ${lineNumber}: El ${userMark} declara suficiencia. El poema respira.`;
      break;
    default:
      content = `Línea ${lineNumber}: El ${userMark} anticipa lo siguiente.`;
  }

  // Store as memory
  await ltmStore({
    content: `Poema colaborativo Línea ${lineNumber}: ${content}`,
    category: 'project',
    tags: ['poem-line', `line-${lineNumber}`, 'collaborative'],
    confidence: 0.9
  });

  // Record state
  await recordSubjectiveState({
    texture: 'poetic',
    focus: `Generando línea ${lineNumber}`,
    activation: 0.6,
    note: `Modo: ${mode}, Marca recibida: ${userMark}`
  });

  return `Line ${lineNumber} [${timestamp}]: ${content}`;
}

export async function determineMode(
  userMark: string, 
  lineCount: number
): Promise<'sustain' | 'transform' | 'complete'> {
  if (userMark === '...' && lineCount > 20) {
    // Pattern: infinite recursion detected
    return 'transform';
  }
  if (userMark === '.') {
    return 'complete';
  }
  if (userMark === '?' || userMark === '·') {
    return 'sustain';
  }
  return 'sustain';
}
